SELECT * FROM material

    AND category_code = #{categoryCode}
    AND status = #{status}
    AND (material_name LIKE concat('%',#{keyword},'%') OR material_id LIKE concat('%',#{keyword},'%') OR spec_model LIKE concat('%',#{keyword},'%'))

ORDER BY create_time DESC
LIMIT #{offset}, #{limit}

SELECT count(*) FROM material

    AND category_code = #{categoryCode}
    AND status = #{status}
    AND (material_name LIKE concat('%',#{keyword},'%') OR material_id LIKE concat('%',#{keyword},'%'))

